COUNTY_FIPS.update(_SIMPLE_STATES)


def get_counties_for_state(state_abbr: str) -> dict[str, str]:
    """Return {fips5: county_name} for the given state."""
    return COUNTY_FIPS.get(state_abbr, {})


def search_county(state_abbr: str, query: str) -> dict[str, str]:
    """Case-insensitive substring search on county names."""
    q = query.lower()
    return {
        fips: name
        for fips, name in get_counties_for_state(state_abbr).items()
        if q in name.lower()
    }
